mapper.select:
select match_user_name as typeName, round(sum(total_amount) / 10000, 2) as money, round(sum(total_number), 2) as tonnes, count(match_user_id) num, match_user_id userId, #{statisticsType} as statisticsType from t_ctr_contract c where contract_status != 'C' and business_type = 'ZY-BB' and contract_type = 'S'
AND date_format(seal_date, '%Y-%m') = #{dayOrMonth}
AND date_format(delivery_date_to, '%Y-%m') = #{dayOrMonth}
and match_credit_flg = #{matchCreditFlg}
and match_user_id in
#{item}
and c.match_user_id not in
#{hgMatchUserIdList[${index}]}
group by match_user_id order by sum(total_amount) desc limit 7

select date_format(s.seal_date, '%Y-%m') month, ROUND(SUM(if(our.company_name is NULL, s.total_amount - dcsx.total_amount, dcsx.total_amount-b.total_amount) + IFNULL((s.breach_amount*s.breach_days*0.1)/365,0) - IFNULL(s.receive_breach_amount,0))/1.13/10000,6) dcsxCapitalCost FROM t_ctr_contract_settlement r INNER JOIN t_ctr_contract b ON b.id = r.buy_contract_id INNER JOIN t_ctr_contract s ON s.id = r.sell_contract_id LEFT JOIN t_ctr_dcsx dcsx ON dcsx.approve_id = b.approve_id LEFT JOIN t_bs_company_our our ON dcsx.our_company_name = our.company_name AND our.our_company_flag=TRUE LEFT JOIN t_bs_company_our our2 ON dcsx.company_name = our2.company_name AND our2.our_company_flag=TRUE where s.business_type = 'ZY-BB' and s.match_credit_flg = TRUE and s.business_type_dcsx IN ('DCSXBL', 'DCSX', 'DCSXHDFK') and s.seal_flg = TRUE and b.seal_flg = TRUE and s.status != 'C' and b.status != 'C'
and s.dept_id in
#{deptIdList[${index}],jdbcType=VARCHAR}
and date_format(s.seal_date, '%Y-%m') in
#{eighteenMonthList[${index}],jdbcType=VARCHAR}
group by date_format(s.seal_date, '%Y-%m') order by s.seal_date

select date_format(s.seal_date, '%Y-%m') month, ROUND(SUM(IFNULL(r.financial_service_amount,0))/1.13/10000,6) capitalCost FROM t_ctr_contract_settlement r INNER JOIN t_ctr_contract b ON b.id = r.buy_contract_id INNER JOIN t_ctr_contract s ON s.id = r.sell_contract_id where s.business_type = 'ZY-BB' and s.match_credit_flg = TRUE and s.business_type_dcsx not IN ('DCSXBL', 'DCSX', 'DCSXHDFK') and s.seal_flg = TRUE and b.seal_flg = TRUE and s.status != 'C' and b.status != 'C'
and s.dept_id in
#{deptIdList[${index}],jdbcType=VARCHAR}
and date_format(s.seal_date, '%Y-%m') in
#{eighteenMonthList[${index}],jdbcType=VARCHAR}
group by date_format(s.seal_date, '%Y-%m') order by s.seal_date

select *
from t_ctr_contract
where date_format(contract_time, '%Y-%m') = #{baseDate}
  and match_user_id in

    #{item.matchUserId}
